"use client"

import React, { useEffect, useMemo, useState } from "react"
import { apiDelete, apiGet, apiPost, apiPut } from "@/lib/api"
import {
    ShieldCheck,
    RefreshCw,
    Save,
    AlertTriangle,
    CheckCircle2,
    Info,
    Search,
    Trash2,
    Plus,
    Lock,
    Eye,
    EyeOff,
    Link2,
    KeyRound,
    Users,
    ChevronRight,
    Settings2,
    X,
} from "lucide-react"

/* ----------------------------- Types ----------------------------- */

type AuthSettingsResponse = {
    ldap?: LdapSettings
    saml?: SamlSettings
}

type LdapSettings = {
    enabled?: boolean
    url?: string
    baseDN?: string
    serviceDN?: string
    servicePassword?: string
    caCert?: string
    allowInsecure?: boolean
}

type SamlSettings = {
    enabled?: boolean
    entryPoint?: string
    issuer?: string
    cert?: string
    callbackUrl?: string
    attributeMapping?: any
}

type SsoMapping = {
    org?: string
    orgId?: string
    provider?: string
    externalGroupId?: string
    externalGroupName?: string
    internalGroup?: string
    createdAt?: string
}

type InternalGroup = { _id: string; groupName: string }

type ExternalGroup = {
    provider: "LDAP" | "SAML"
    externalGroupId: string
    externalGroupName: string
}

/* ----------------------------- Utils ----------------------------- */

function cx(...classes: Array<string | false | null | undefined>) {
    return classes.filter(Boolean).join(" ")
}

function isMongoObjectId(v: string) {
    return /^[a-fA-F0-9]{24}$/.test(v)
}

function safeJsonParse(v: string) {
    try {
        return JSON.parse(v)
    } catch {
        return null
    }
}

function trimOrUndefined(v: any) {
    const s = String(v ?? "").trim()
    return s ? s : undefined
}

function mappingKey(provider: string, externalGroupId: string) {
    return `${provider.toLowerCase()}::${String(externalGroupId || "").trim()}`
}

export default function AuthenticationSettingsPage() {
    const [orgId, setOrgId] = useState<string>("")
    const [orgName, setOrgName] = useState<string>("")
    const [createdByUserId, setCreatedByUserId] = useState<string>("")

    const [activeProvider, setActiveProvider] = useState<"ldap" | "saml">("ldap")
    const [loading, setLoading] = useState<boolean>(false)
    const [saving, setSaving] = useState<boolean>(false)
    const [error, setError] = useState<string>("")
    const [notice, setNotice] = useState<string>("")

    const [ldap, setLdap] = useState<LdapSettings>({
        enabled: false,
        url: "",
        baseDN: "",
        serviceDN: "",
        servicePassword: "",
        caCert: "",
        allowInsecure: false,
    })

    const [saml, setSaml] = useState<SamlSettings>({
        enabled: false,
        entryPoint: "",
        issuer: "",
        cert: "",
        callbackUrl: "",
        attributeMapping: {},
    })

    const [snapshot, setSnapshot] = useState<AuthSettingsResponse | null>(null)
    const [showPassword, setShowPassword] = useState(false)
    const [mappings, setMappings] = useState<SsoMapping[]>([])
    const [internalGroups, setInternalGroups] = useState<InternalGroup[]>([])
    const [externalGroups, setExternalGroups] = useState<ExternalGroup[]>([])
    const [newSamlGroupName, setNewSamlGroupName] = useState<string>("")
    const [rowSavingKey, setRowSavingKey] = useState<string>("")
    const [isInfoOpen, setIsInfoOpen] = useState(false)

    useEffect(() => {
        async function init() {
            try {
                const res: any = await apiGet("/users/auth/me")
                if (res.success && res.user) {
                    setOrgId(res.user.org?._id || res.user.orgId)
                    setCreatedByUserId(res.user._id || res.user.userId)
                    setOrgName(res.user.org?.orgName || "")
                }
            } catch (err) {
                console.error("Failed to init auth settings:", err)
            }
        }
        init()
    }, [])

    async function loadData() {
        if (!orgId) return
        setLoading(true)
        try {
            const [authRes, groupsRes] = await Promise.all([
                apiGet<any>(`/org/auth-settings`),
                apiGet<any>(`/sso/groups`),
            ])

            const authData = authRes?.data ?? authRes ?? {}
            setLdap({
                enabled: !!authData.ldap?.enabled,
                url: authData.ldap?.url || "",
                baseDN: authData.ldap?.baseDN || "",
                serviceDN: authData.ldap?.serviceDN || "",
                servicePassword: "",
                caCert: authData.ldap?.caCert || "",
                allowInsecure: !!authData.ldap?.allowInsecure,
            })
            setSaml({
                enabled: !!authData.saml?.enabled,
                entryPoint: authData.saml?.entryPoint || "",
                issuer: authData.saml?.issuer || "",
                cert: authData.saml?.cert || "",
                callbackUrl: authData.saml?.callbackUrl || "",
                attributeMapping: authData.saml?.attributeMapping ?? {},
            })
            setSnapshot({ ldap: authData.ldap, saml: authData.saml })

            if (authData.saml?.enabled) setActiveProvider("saml")

            setMappings(groupsRes.mappings || [])
            setInternalGroups(groupsRes.internalGroups || [])

            const ad = (groupsRes.adGroups || []).map((g: any) => ({
                provider: "LDAP",
                externalGroupId: g.dn || g.id,
                externalGroupName: g.name || g.displayName,
            }))
            const sm = (groupsRes.samlGroups || []).map((g: any) => ({
                provider: "SAML",
                externalGroupId: g.id || g.groupId,
                externalGroupName: g.name || g.displayName,
            }))
            setExternalGroups([...ad, ...sm])

        } catch (e: any) {
            setError(e?.message || "Failed to load configuration")
        } finally {
            setLoading(false)
        }
    }

    useEffect(() => {
        if (orgId) loadData()
    }, [orgId])

    async function handleSave() {
        setSaving(true)
        setError("")
        setNotice("")

        try {
            if (activeProvider === "ldap") {
                // Mandatory fields for LDAP
                if (!ldap.url?.trim()) throw new Error("LDAP URL is required")
                if (!ldap.baseDN?.trim()) throw new Error("Base DN is required")
                if (!ldap.serviceDN?.trim()) throw new Error("Service DN is required")

                // Password only required if not already set or if explicitly being changed
                if (!ldap.servicePassword?.trim() && !snapshot?.ldap?.enabled) {
                    throw new Error("Service Password is required for first-time setup")
                }

                await apiPut("/org/ldap", {
                    enabled: !!ldap.enabled,
                    url: ldap.url,
                    baseDN: ldap.baseDN,
                    serviceDN: ldap.serviceDN,
                    servicePassword: ldap.servicePassword || undefined,
                    caCert: ldap.caCert || null,
                    allowInsecure: !!ldap.allowInsecure
                })
            } else {
                // Mandatory fields for SAML
                if (!saml.entryPoint?.trim()) throw new Error("Entry Point is required")
                if (!saml.issuer?.trim()) throw new Error("Issuer is required")
                if (!saml.callbackUrl?.trim()) throw new Error("Callback URL is required")

                await apiPut("/org/saml", {
                    enabled: !!saml.enabled,
                    entryPoint: saml.entryPoint,
                    issuer: saml.issuer,
                    cert: saml.cert || undefined,
                    callbackUrl: saml.callbackUrl,
                    attributeMapping: saml.attributeMapping
                })
            }
            setNotice("Settings updated successfully")
            loadData()
        } catch (e: any) {
            setError(e?.message || "Failed to save settings")
        } finally {
            setSaving(false)
        }
    }

    async function handleMappingUpdate(g: ExternalGroup, internalId: string) {
        const key = mappingKey(g.provider, g.externalGroupId)
        setRowSavingKey(key)
        try {
            if (!internalId) {
                // Detach mapping
                await apiDelete(`/sso/map/${g.provider}/${encodeURIComponent(g.externalGroupId)}`)
                setNotice("Mapping detached")
            } else {
                // Update mapping
                await apiPost("/sso/map", {
                    provider: g.provider,
                    externalGroupId: g.externalGroupId,
                    externalGroupName: g.externalGroupName,
                    internalGroup: internalId,
                })
                setNotice("Mapping updated")
            }
            const groupsRes = await apiGet<any>(`/sso/groups`)
            setMappings(groupsRes.mappings || [])
        } catch (e: any) {
            setError(e?.message || "Failed to update mapping")
        } finally {
            setRowSavingKey("")
        }
        async function handleAddManualGroup() {
            if (!newSamlGroupName.trim()) return
            const groupName = newSamlGroupName.trim()

            // Prevent duplicates in state
            if (externalGroups.some(g => g.provider === "SAML" && g.externalGroupId === groupName)) {
                setNotice("Group already exists in the list")
                return
            }

            const newGroup: ExternalGroup = {
                provider: "SAML",
                externalGroupId: groupName,
                externalGroupName: groupName
            }

            setExternalGroups(prev => [...prev, newGroup])
            setNewSamlGroupName("")
            setNotice("Added manual SAML group. You can now map it below.")
        }

        return (
            <div className="space-y-6">
                <div className="flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
                    <div>
                        <div className="flex items-center gap-2 text-xs text-slate-400">
                            Settings <ChevronRight className="h-3 w-3" /> <span className="text-slate-200">Authentication</span>
                        </div>
                        <h1 className="mt-1 text-2xl font-semibold tracking-tight text-slate-100 font-inter">Authentication & SSO</h1>
                        <p className="mt-1 text-sm text-slate-400">Manage how your team signs into PromptProtect.</p>
                    </div>

                    <div className="flex items-center gap-3">
                        <div className="rounded-2xl border border-slate-800 bg-slate-900/40 px-3 py-2">
                            <div className="text-[10px] uppercase font-bold text-slate-500 tracking-wider">Organization</div>
                            <div className="text-sm font-semibold text-slate-200">{orgName || orgId}</div>
                        </div>
                        <button
                            onClick={loadData}
                            disabled={loading}
                            className="flex items-center gap-2 rounded-2xl border border-slate-800 bg-slate-900/40 px-4 py-2 text-sm font-semibold text-slate-300 hover:bg-slate-900/60 transition"
                        >
                            <RefreshCw className={cx("h-4 w-4", loading && "animate-spin")} />
                            Refresh
                        </button>
                    </div>
                </div>

                {(error || notice) && (
                    <div className={cx("rounded-2xl border p-4 flex items-start gap-3", error ? "border-red-500/25 bg-red-500/5" : "border-emerald-500/25 bg-emerald-500/5")}>
                        {error ? <AlertTriangle className="h-5 w-5 text-red-400 shrink-0" /> : <CheckCircle2 className="h-5 w-5 text-emerald-400 shrink-0" />}
                        <div className="text-sm text-slate-200">{error || notice}</div>
                    </div>
                )}

                <div className="relative flex-1 overflow-x-hidden">
                    <div className={`transition-all duration-300 ${isInfoOpen ? "mr-[350px]" : "mr-0"}`}>
                        <div className="grid grid-cols-1 gap-6">
                            <div className="space-y-6">
                                <div className="flex gap-4 p-2">
                                    <label className={cx("flex flex-1 items-center gap-3 cursor-pointer p-4 rounded-xl border transition-all", activeProvider === "ldap" ? "border-blue-500/50 bg-blue-500/10" : "border-slate-800 bg-slate-900/40 hover:border-slate-700")}>
                                        <div className={cx("flex h-5 w-5 items-center justify-center rounded-full border", activeProvider === "ldap" ? "border-blue-500" : "border-slate-600")}>
                                            {activeProvider === "ldap" && <div className="h-2.5 w-2.5 rounded-full bg-blue-500" />}
                                        </div>
                                        <input
                                            type="radio"
                                            name="authProvider"
                                            className="hidden"
                                            checked={activeProvider === "ldap"}
                                            onChange={() => setActiveProvider("ldap")}
                                        />
                                        <div className="flex flex-col">
                                            <span className="text-sm font-semibold text-slate-200">LDAP / Active Directory</span>
                                            <span className="text-xs text-slate-400">Connect to on-premise AD</span>
                                        </div>
                                    </label>

                                    <label className={cx("flex flex-1 items-center gap-3 cursor-pointer p-4 rounded-xl border transition-all", activeProvider === "saml" ? "border-blue-500/50 bg-blue-500/10" : "border-slate-800 bg-slate-900/40 hover:border-slate-700")}>
                                        <div className={cx("flex h-5 w-5 items-center justify-center rounded-full border", activeProvider === "saml" ? "border-blue-500" : "border-slate-600")}>
                                            {activeProvider === "saml" && <div className="h-2.5 w-2.5 rounded-full bg-blue-500" />}
                                        </div>
                                        <input
                                            type="radio"
                                            name="authProvider"
                                            className="hidden"
                                            checked={activeProvider === "saml"}
                                            onChange={() => setActiveProvider("saml")}
                                        />
                                        <div className="flex flex-col">
                                            <span className="text-sm font-semibold text-slate-200">SAML 2.0</span>
                                            <span className="text-xs text-slate-400">Okta, Azure AD, OneLogin</span>
                                        </div>
                                    </label>
                                </div>

                                <div className="rounded-3xl border border-slate-800 bg-slate-950/40 backdrop-blur-sm overflow-hidden">
                                    <div className="border-b border-slate-800 p-6 flex items-center justify-between">
                                        <div>
                                            <h3 className="text-lg font-semibold text-slate-100">{activeProvider === "ldap" ? "LDAP Configuration" : "SAML Configuration"}</h3>
                                            <p className="text-sm text-slate-400">{activeProvider === "ldap" ? "Connect your on-premise AD or LDAP." : "Use Okta, Azure AD, or any SAML provider."}</p>
                                        </div>
                                        <div className={cx("px-3 py-1 rounded-full text-[10px] font-bold tracking-widest uppercase border", (activeProvider === "ldap" ? ldap.enabled : saml.enabled) ? "border-emerald-500/30 bg-emerald-500/10 text-emerald-400" : "border-slate-800 bg-slate-900/40 text-slate-500")}>
                                            {(activeProvider === "ldap" ? ldap.enabled : saml.enabled) ? "Active" : "Disabled"}
                                        </div>
                                    </div>

                                    <div className="p-6 space-y-6">
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                            <Toggle
                                                label={`Enable ${activeProvider.toUpperCase()}`}
                                                checked={activeProvider === "ldap" ? !!ldap.enabled : !!saml.enabled}
                                                onChange={(v) => activeProvider === "ldap" ? setLdap({ ...ldap, enabled: v }) : setSaml({ ...saml, enabled: v })}
                                            />

                                            {activeProvider === "ldap" ? (
                                                <>
                                                    <Input label="LDAP URL" value={ldap.url || ""} onChange={(v) => setLdap({ ...ldap, url: v })} placeholder="ldaps://ldap.company.com:636" />
                                                    <Input label="Base DN" value={ldap.baseDN || ""} onChange={(v) => setLdap({ ...ldap, baseDN: v })} placeholder="DC=company,DC=com" />
                                                    <Input label="Service DN" value={ldap.serviceDN || ""} onChange={(v) => setLdap({ ...ldap, serviceDN: v })} placeholder="CN=admin,OU=Users,DC=company" />
                                                    <div className="relative">
                                                        <Input label="Service Password" type={showPassword ? "text" : "password"} value={ldap.servicePassword || ""} onChange={(v) => setLdap({ ...ldap, servicePassword: v })} placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó" />
                                                        <button onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-[34px] text-slate-500 hover:text-slate-300">
                                                            {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                                                        </button>
                                                    </div>
                                                    <Toggle
                                                        label="Allow Insecure Connections"
                                                        checked={!!ldap.allowInsecure}
                                                        onChange={(v) => setLdap({ ...ldap, allowInsecure: v })}
                                                    />
                                                    <TextArea label="CA Certificate (Optional)" value={ldap.caCert || ""} onChange={(v) => setLdap({ ...ldap, caCert: v })} placeholder="-----BEGIN CERTIFICATE-----" />
                                                </>
                                            ) : (
                                                <>
                                                    <Input label="Entry Point" value={saml.entryPoint || ""} onChange={(v) => setSaml({ ...saml, entryPoint: v })} placeholder="https://okta.com/auth/..." />
                                                    <Input label="Issuer" value={saml.issuer || ""} onChange={(v) => setSaml({ ...saml, issuer: v })} placeholder="promptprotect-sp" />
                                                    <Input label="Callback URL" value={saml.callbackUrl || ""} onChange={(v) => setSaml({ ...saml, callbackUrl: v })} placeholder="https://api.promptprotect.com/saml/callback" />
                                                    <TextArea label="Certificate" value={saml.cert || ""} onChange={(v) => setSaml({ ...saml, cert: v })} placeholder="-----BEGIN CERTIFICATE-----" />
                                                </>
                                            )}
                                        </div>

                                        <div className="flex justify-end pt-4">
                                            <button
                                                onClick={handleSave}
                                                disabled={saving}
                                                className="flex items-center gap-2 rounded-2xl bg-blue-600 px-6 py-2.5 text-sm font-semibold text-white hover:bg-blue-500 transition disabled:opacity-50 shadow-lg shadow-blue-900/20"
                                            >
                                                {saving ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                                                Save Changes
                                            </button>
                                        </div>
                                    </div>
                                </div>
                                <div className="rounded-3xl border border-slate-800 bg-slate-950/40 backdrop-blur-sm overflow-hidden">
                                    <div className="border-b border-slate-800 p-6 flex items-center justify-between">
                                        <div>
                                            <h3 className="text-lg font-semibold text-slate-100">SSO Group Mappings</h3>
                                            <p className="text-sm text-slate-400">Map your {activeProvider.toUpperCase()} groups to local PromptProtect groups.</p>
                                        </div>
                                    </div>
                                    <div className="p-6">
                                        {activeProvider === "saml" && (
                                            <div className="mb-6 flex gap-3 items-end p-4 rounded-xl border border-slate-800 bg-slate-900/40">
                                                <div className="flex-1">
                                                    <Input
                                                        label="Add Manual SAML Group"
                                                        value={newSamlGroupName}
                                                        onChange={setNewSamlGroupName}
                                                        placeholder="Enter exact SAML group name (e.g., 'Engineering')"
                                                    />
                                                </div>
                                                <button
                                                    onClick={handleAddManualGroup}
                                                    disabled={!newSamlGroupName.trim()}
                                                    className="flex h-[42px] items-center gap-2 rounded-xl bg-slate-800 px-4 text-sm font-semibold text-slate-200 hover:bg-slate-700 disabled:opacity-50 transition"
                                                >
                                                    <Plus className="h-4 w-4" />
                                                    Add Group
                                                </button>
                                            </div>
                                        )}

                                        <div className="overflow-x-auto">
                                            <table className="w-full text-left text-sm">
                                                <thead>
                                                    <tr className="border-b border-slate-800 text-slate-400 font-medium">
                                                        <th className="pb-3 pr-4">External Group Name</th>
                                                        <th className="pb-3 pr-4">PromptProtect Group</th>
                                                        <th className="pb-3 w-10"></th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-slate-800">
                                                    {externalGroups.filter(g => g.provider.toLowerCase() === activeProvider).map((g) => {
                                                        const mapping = mappings.find(m => m.externalGroupId === g.externalGroupId)
                                                        return (
                                                            <tr key={g.externalGroupId} className="group hover:bg-slate-900/20 transition">
                                                                <td className="py-4 pr-4">
                                                                    <div className="font-semibold text-slate-200">{g.externalGroupName}</div>
                                                                    <div className="text-[10px] text-slate-500 font-mono mt-0.5 max-w-[200px] truncate">{g.externalGroupId}</div>
                                                                </td>
                                                                <td className="py-4 pr-4">
                                                                    <div className="relative group/select">
                                                                        <select
                                                                            value={mapping?.internalGroup || ""}
                                                                            onChange={(e) => handleMappingUpdate(g, e.target.value)}
                                                                            disabled={rowSavingKey === mappingKey(g.provider, g.externalGroupId)}
                                                                            className="w-full appearance-none rounded-xl border border-slate-800 bg-slate-950/40 px-4 py-2 text-xs text-slate-200 outline-none focus:border-blue-500/50 hover:border-slate-700 transition-all cursor-pointer disabled:opacity-50"
                                                                        >
                                                                            <option value="" className="bg-slate-950 text-slate-400">-- No Mapping --</option>
                                                                            {internalGroups.map(ig => (
                                                                                <option key={ig._id} value={ig._id} className="bg-slate-950 text-slate-200">
                                                                                    {ig.groupName}
                                                                                </option>
                                                                            ))}
                                                                        </select>
                                                                        <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 group-hover/select:text-slate-300 transition-colors">
                                                                            <ChevronRight className="h-3 w-3 rotate-90" />
                                                                        </div>
                                                                    </div>
                                                                </td>
                                                                <td className="py-4">
                                                                    {rowSavingKey === mappingKey(g.provider, g.externalGroupId) && <RefreshCw className="h-4 w-4 animate-spin text-blue-400" />}
                                                                    {mapping && rowSavingKey !== mappingKey(g.provider, g.externalGroupId) && <CheckCircle2 className="h-4 w-4 text-emerald-400" />}
                                                                </td>
                                                            </tr>
                                                        )
                                                    })}
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Quick Info Drawer */}
                    <div className={`fixed top-0 right-0 h-full w-[350px] bg-slate-900/80 backdrop-blur-xl border-l border-white/5 shadow-2xl transition-transform duration-300 ease-in-out z-40 ${isInfoOpen ? "translate-x-0" : "translate-x-full"}`}>
                        <div className="h-full flex flex-col p-6 pt-24">
                            <div className="flex items-center justify-between mb-8">
                                <h4 className="flex items-center gap-2 text-lg font-semibold text-slate-100">
                                    <Info className="h-5 w-5 text-blue-400" />
                                    Quick Info
                                </h4>
                                <button onClick={() => setIsInfoOpen(false)} className="rounded-xl border border-white/10 p-2 hover:bg-white/5 transition">
                                    <X className="h-4 w-4 text-slate-400" />
                                </button>
                            </div>

                            <div className="space-y-8 text-sm leading-relaxed text-slate-400 overflow-y-auto">

                                {/* ================= SAML ================= */}
                                <div className="space-y-3">
                                    <p className="font-semibold text-slate-200">SAML Configuration Guide</p>
                                    <p>
                                        To configure SAML SSO, create a new SAML 2.0 application in your Identity Provider (Okta, Azure AD, OneLogin, etc.)
                                        and provide the following values:
                                    </p>

                                    <div className="bg-slate-900/40 rounded-2xl p-4 border border-slate-800/50 font-mono text-xs space-y-3">
                                        <div>
                                            <div className="text-slate-500 uppercase tracking-wider text-[10px]">ACS (Callback) URL</div>
                                            <div className="text-blue-300 break-all">https://your-domain.com/saml/callback/...</div>
                                        </div>

                                        <div>
                                            <div className="text-slate-500 uppercase tracking-wider text-[10px]">Entity ID (SP Entity ID)</div>
                                            <div className="text-blue-300 break-all">https://your-domain.com/saml/metadata/...</div>
                                        </div>

                                        <div>
                                            <div className="text-slate-500 uppercase tracking-wider text-[10px]">NameID Format</div>
                                            <div className="text-blue-300">EmailAddress</div>
                                        </div>
                                    </div>

                                    <p className="mt-3">
                                        After creating the app in your IdP, collect the following values and paste them into this configuration:
                                    </p>

                                    <ul className="list-disc pl-5 space-y-2 text-slate-400">
                                        <li>IdP SSO URL (Single Sign-On URL)</li>
                                        <li>IdP Entity ID</li>
                                        <li>X.509 Certificate (Public Certificate)</li>
                                    </ul>

                                    <p className="text-slate-500 text-xs mt-2">
                                        Ensure that the email attribute is mapped correctly, as it is used for user identification and provisioning.
                                    </p>
                                </div>


                                {/* ================= LDAP ================= */}
                                <div className="space-y-3">
                                    <p className="font-semibold text-slate-200">LDAP Configuration Guide</p>
                                    <p>
                                        Connect your organization to Active Directory or any LDAP-compatible directory for direct authentication.
                                    </p>

                                    <ul className="list-disc pl-5 space-y-2 text-slate-400">
                                        <li><strong>LDAP URL</strong> ΓÇö Example: ldaps://ad.company.local:636</li>
                                        <li><strong>Base DN</strong> ΓÇö Example: OU=Employees,DC=company,DC=local</li>
                                        <li><strong>Service DN</strong> ΓÇö Bind account used to search users</li>
                                        <li><strong>Service Password</strong> ΓÇö Password of the bind account</li>
                                    </ul>

                                    <p>
                                        The Service DN must have read permissions to query users within the specified Base DN.
                                    </p>

                                    <p className="text-slate-500 text-xs">
                                        Use LDAPS (port 636) for secure encrypted communication. Avoid enabling insecure mode unless testing.
                                    </p>
                                </div>


                                {/* ================= Security Note ================= */}
                                <div className="bg-slate-900/40 rounded-2xl p-4 border border-slate-800/50 mt-4">
                                    <p className="font-medium text-slate-300 mb-2">Important</p>
                                    <p className="text-slate-400 text-xs">
                                        Only one authentication provider (LDAP or SAML) can be active at a time.
                                        Switching providers will disable the currently active configuration.
                                    </p>
                                </div>

                            </div>


                        </div>
                    </div>

                    {/* Info Toggle Button */}
                    {!isInfoOpen && (
                        <button
                            onClick={() => setIsInfoOpen(true)}
                            className="fixed right-0 top-[35%] bg-blue-600 hover:bg-blue-500 text-white p-3 rounded-l-2xl shadow-lg shadow-blue-900/20 transition-all z-30 group"
                            title="Show Quick Info"
                        >
                            <Info className="h-5 w-5 group-hover:scale-110 transition-transform" />
                        </button>
                    )}
                </div>
            </div>
        )
    }

    function Toggle({ label, checked, onChange }: { label: string; checked: boolean; onChange: (v: boolean) => void }) {
        return (
            <div className="flex items-center justify-between p-4 rounded-2xl border border-slate-800 bg-slate-900/20">
                <span className="text-sm font-semibold text-slate-200">{label}</span>
                <button
                    onClick={() => onChange(!checked)}
                    className={cx("w-10 h-5 rounded-full relative transition-colors", checked ? "bg-blue-600" : "bg-slate-700")}
                >
                    <div className={cx("absolute top-1 w-3 h-3 rounded-full bg-white transition-all", checked ? "right-1" : "right-6")} />
                </button>
            </div>
        )
    }

    function Input({ label, value, onChange, placeholder, type = "text" }: { label: string; value: string; onChange: (v: string) => void; placeholder?: string; type?: string }) {
        return (
            <div className="space-y-1.5">
                <label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider ml-1">{label}</label>
                <input
                    type={type}
                    value={value}
                    onChange={(e) => onChange(e.target.value)}
                    placeholder={placeholder}
                    className="w-full rounded-2xl border border-slate-800 bg-slate-950/60 px-4 py-2.5 text-sm text-slate-100 placeholder:text-slate-600 outline-none focus:border-blue-500/40 transition-colors"
                />
            </div>
        )
    }

    function TextArea({ label, value, onChange, placeholder }: { label: string; value: string; onChange: (v: string) => void; placeholder?: string }) {
        return (
            <div className="space-y-1.5 md:col-span-2">
                <label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider ml-1">{label}</label>
                <textarea
                    value={value}
                    onChange={(e) => onChange(e.target.value)}
                    placeholder={placeholder}
                    rows={4}
                    className="w-full rounded-2xl border border-slate-800 bg-slate-950/60 px-4 py-2.5 text-xs text-slate-100 font-mono placeholder:text-slate-600 outline-none focus:border-blue-500/40 transition-colors resize-none"
                />
            </div>
        )
    }
}
